import React, { useState } from 'react';
import { Plus } from 'lucide-react';

const TodoForm = ({ addTodo }) => {
  const [task, setTask] = useState('');

  const handleSubmit = (e) => {
    e.preventDefault();
    if (task.trim()) {
      addTodo(task);
      setTask('');
    }
  };

  return (
    <form onSubmit={handleSubmit} className="flex items-center gap-2 p-4 bg-white rounded-lg shadow-md mb-6">
      <input
        type="text"
        value={task}
        onChange={(e) => setTask(e.target.value)}
        placeholder="What needs to be done?"
        aria-label="Add new todo task"
        className="flex-grow p-3 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-400 text-gray-800 text-base md:text-lg transition-all duration-200 ease-in-out"
      />
      <button
        type="submit"
        className="flex-shrink-0 px-5 py-3 bg-primary-500 text-white rounded-md hover:bg-primary-600 focus:outline-none focus:ring-2 focus:ring-primary-400 focus:ring-offset-2 transition-all duration-200 ease-in-out flex items-center gap-2 text-base md:text-lg font-medium shadow-sm hover:shadow-md"
        aria-label="Add task"
      >
        <Plus size={20} />
        Add Task
      </button>
    </form>
  );
};

export default TodoForm;

