import React, { useState, useEffect } from 'react';
import TodoForm from './TodoForm';
import TodoItem from './TodoItem';
import useTodos from '../hooks/useTodos';

const TodoList = () => {
  const { todos, addTodo, toggleComplete, deleteTodo, editTodo } = useTodos();
  const [filter, setFilter] = useState('all'); // 'all', 'active', 'completed'
  const [searchTerm, setSearchTerm] = useState('');

  const filteredTodos = todos.filter(todo => {
    const matchesFilter = filter === 'all' ||
                          (filter === 'active' && !todo.completed) ||
                          (filter === 'completed' && todo.completed);
    const matchesSearch = todo.text.toLowerCase().includes(searchTerm.toLowerCase());
    return matchesFilter && matchesSearch;
  });

  const remainingTasks = todos.filter(todo => !todo.completed).length;

  return (
    <div className="container mx-auto p-4 sm:p-6 lg:p-8 max-w-2xl bg-white shadow-xl rounded-2xl my-8 font-sans">
      <h1 className="text-4xl font-display font-extrabold text-gray-900 mb-8 text-center">
        My Daily Tasks
      </h1>

      <TodoForm addTodo={addTodo} />

      <div className="flex flex-col sm:flex-row items-center justify-between mt-8 mb-6 gap-4">
        <div className="flex space-x-2 sm:space-x-3">
          <button
            onClick={() => setFilter('all')}
            className={`px-4 py-2 rounded-full text-sm font-medium transition-all duration-200
              ${filter === 'all' ? 'bg-primary-500 text-white shadow-md' : 'bg-gray-100 text-gray-700 hover:bg-gray-200'}`}
            aria-pressed={filter === 'all'}
          >
            All
          </button>
          <button
            onClick={() => setFilter('active')}
            className={`px-4 py-2 rounded-full text-sm font-medium transition-all duration-200
              ${filter === 'active' ? 'bg-primary-500 text-white shadow-md' : 'bg-gray-100 text-gray-700 hover:bg-gray-200'}`}
            aria-pressed={filter === 'active'}
          >
            Active
          </button>
          <button
            onClick={() => setFilter('completed')}
            className={`px-4 py-2 rounded-full text-sm font-medium transition-all duration-200
              ${filter === 'completed' ? 'bg-primary-500 text-white shadow-md' : 'bg-gray-100 text-gray-700 hover:bg-gray-200'}`}
            aria-pressed={filter === 'completed'}
          >
            Completed
          </button>
        </div>
        <div className="relative w-full sm:w-auto">
          <input
            type="text"
            placeholder="Search tasks..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="pl-10 pr-4 py-2 w-full sm:w-64 border border-gray-300 rounded-full focus:ring-2 focus:ring-primary-200 focus:border-primary-400 transition-all duration-200 text-sm"
            aria-label="Search tasks"
          />
          <svg
            className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400"
            xmlns="http://www.w3.org/2000/svg"
            width="18"
            height="18"
            viewBox="0 0 24 24"
            fill="none"
            stroke="currentColor"
            strokeWidth="2"
            strokeLinecap="round"
            strokeLinejoin="round"
          >
            <circle cx="11" cy="11" r="8"></circle>
            <line x1="21" y1="21" x2="16.65" y2="16.65"></line>
          </svg>
        </div>
      </div>

      {filteredTodos.length === 0 && (
        <p className="text-center text-gray-500 text-lg mt-10 p-4 bg-gray-50 rounded-lg">
          {todos.length === 0 ? "You have no tasks yet. Add one above!" : "No tasks match your current filter or search."}
        </p>
      )}

      <ul className="space-y-4 mt-6">
        {filteredTodos.map(todo => (
          <TodoItem
            key={todo.id}
            todo={todo}
            toggleComplete={toggleComplete}
            deleteTodo={deleteTodo}
            editTodo={editTodo}
          />
        ))}
      </ul>

      <div className="mt-8 pt-6 border-t border-gray-200 text-gray-600 text-sm flex justify-between items-center">
        <span>{remainingTasks} tasks remaining</span>
        <button
          onClick={() => setFilter('all')}
          className="text-primary-600 hover:text-primary-800 transition-colors duration-200 focus:outline-none focus:ring-2 focus:ring-primary-200 rounded-md px-2 py-1"
        >
          Clear filters
        </button>
      </div>
    </div>
  );
};

export default TodoList;

